DROP TABLE IF EXISTS `main_employees`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `main_employees` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint DEFAULT NULL,
  `date_of_joining` date DEFAULT NULL,
  `date_of_leaving` date DEFAULT NULL,
  `reason_for_leaving` varchar(255) DEFAULT NULL,
  `prob_complete_date` date DEFAULT NULL,
  `reporting_manager` bigint unsigned DEFAULT NULL,
  `emp_status_id` int unsigned DEFAULT NULL,
  `businessunit_id` int unsigned DEFAULT NULL,
  `department_id` int unsigned DEFAULT NULL,
  `organization_id` int DEFAULT NULL,
  `reporting_at` int DEFAULT NULL COMMENT '1-Reporting at office,\r\n2-Reporting at client',
  `jobtitle_id` int unsigned DEFAULT NULL,
  `position_id` int unsigned DEFAULT NULL,
  `project_id` int DEFAULT NULL,
  `years_exp` varchar(20) DEFAULT NULL COMMENT 'for numbers we are using varchar datatype',
  `holiday_group` int unsigned DEFAULT NULL,
  `leave_eligible` int NOT NULL DEFAULT '0',
  `prefix_id` int unsigned DEFAULT NULL,
  `extension_number` varchar(20) DEFAULT NULL COMMENT 'for numbers we are using varchar datatype',
  `office_number` varchar(100) DEFAULT NULL,
  `office_faxnumber` varchar(100) DEFAULT NULL,
  `createdby` int unsigned DEFAULT NULL,
  `modifiedby` int unsigned DEFAULT NULL,
  `createddate` datetime DEFAULT NULL,
  `modifieddate` datetime DEFAULT NULL,
  `isactive` tinyint unsigned DEFAULT '1' COMMENT '1-active,5-deleted',
  `is_orghead` tinyint unsigned DEFAULT '0' COMMENT '1=organisation head,0=normal employee',
  `relieving_letter` text,
  `relieving_letter_number` varchar(255) DEFAULT NULL,
  `relieving_flag` enum('regular','irregular') DEFAULT NULL,
  `relieving_file_id` varchar(45) DEFAULT NULL,
  `immediate_reliving_letter_fileid` varchar(255) DEFAULT NULL,
  `probation_letter` text,
  `probation_letter_number` text,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_user_id` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=424 DEFAULT CHARSET=utf8mb3;
